function resolvePackFromBundle(segment, text) {
  const topic = segmentToLegalTopic(segment);
  if (!topic) return null;

  const bySegment = LEGAL_PACK_BUNDLE.packs_by_segment || {};
  const byTopic = LEGAL_PACK_BUNDLE.packs_by_topic || {};
  let pack = bySegment[segment] || byTopic[topic];
  if (!pack) return null;

  const province = detectProvinceFromText(text);
  if (province && Array.isArray(LEGAL_PACK_BUNDLE.packs_by_topic)) {
    // no-op: province-specific packs use topic_local keys when present
  }
  const localKey = province ? `${topic}__${province}` : null;
  if (localKey && byTopic[localKey]) {
    pack = byTopic[localKey];
  }

  return JSON.parse(JSON.stringify(pack));
}

function assessLegalGate(segment, pack) {
  const required = segmentRequiresLegalKb(segment);
  if (!required) {
    return { required: false, pass: true, block_reason: null };
  }
  if (!pack) {
    return {
      required: true,
      pass: false,
      block_reason: 'MISSING_LEGAL_PACK',
      needs_human_legal_source: true,
    };
  }
  if (pack.needs_human_legal_source === true) {
    return {
      required: true,
      pass: false,
      block_reason: 'NEEDS_HUMAN_LEGAL_SOURCE',
      needs_human_legal_source: true,
    };
  }
  if (!Array.isArray(pack.facts) || pack.facts.length === 0) {
    return {
      required: true,
      pass: false,
      block_reason: 'EMPTY_LEGAL_FACTS',
      needs_human_legal_source: true,
    };
  }
  return {
    required: true,
    pass: true,
    block_reason: null,
    needs_human_legal_source: false,
    fact_count: pack.facts.length,
  };
}

function buildMinimalBlockedPack(segment, reason) {
  return {
    topic: segmentToLegalTopic(segment) || 'unknown',
    intent: 'short_legal_explainer',
    facts: [],
    forbidden_claims: DEFAULT_FORBIDDEN,
    disclaimer_required: true,
    needs_human_legal_source: true,
    block_reason: reason,
  };
}


const row = $('Loop Brief Candidates').item?.json || $input.first().json;
const segment = String(row.segment || '').trim().toLowerCase();
const text = String(row.text || '');

if (!segmentRequiresLegalKb(segment)) {
  return [{
    json: {
      ...row,
      legal_gate: { required: false, pass: true },
      legal_retrieval_pack: null,
    },
  }];
}

let pack = resolvePackFromBundle(segment, text);
const gate = assessLegalGate(segment, pack);

if (!pack && !gate.pass) {
  pack = buildMinimalBlockedPack(segment, gate.block_reason);
}

return [{
  json: {
    ...row,
    legal_retrieval_pack: pack,
    legal_gate: gate,
    legal_topic: segmentToLegalTopic(segment),
  },
}];

const MAGNIX_LLM_DEFAULTS = {"classify":"deepseek","editorial_brief":"deepseek","outreach":"deepseek","video_draft":"deepseek","carousel_draft":"deepseek","content_draft":"anthropic","content_draft_general":"deepseek","content_qa":"anthropic"};

function hasLlmKey(raw) {
  return String(raw || '').trim().length > 12;
}

function envProvider(taskId) {
  const key = `MAGNIX_LLM_${String(taskId || '')
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '_')}_PROVIDER`;
  const v = String($env[key] || '').trim().toLowerCase();
  if (v === 'deepseek' || v === 'anthropic') return v;
  return null;
}

function resolveProvider(taskId) {
  return envProvider(taskId) || MAGNIX_LLM_DEFAULTS[taskId] || 'deepseek';
}

function hasProvider(provider) {
  if (provider === 'anthropic') return hasLlmKey($env.ANTHROPIC_API_KEY);
  return hasLlmKey($env.DEEPSEEK_API_KEY);
}

function anthropicModelForTask(taskId) {
  if (taskId === 'classify') {
    return $env.ANTHROPIC_CLASSIFY_MODEL || 'claude-haiku-4-5-20251001';
  }
  if (taskId === 'video_draft') {
    return $env.ANTHROPIC_VIDEO_MODEL || $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
  }
  return $env.ANTHROPIC_DRAFT_MODEL || $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6';
}

async function callDeepSeekLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    jsonMode = true,
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
    headers: {
      Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
      temperature,
      max_tokens: maxTokens,
      ...(jsonMode ? { response_format: { type: 'json_object' } } : {}),
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPayload },
      ],
    },
    json: true,
  });
}

async function callAnthropicLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    taskId = 'content_draft',
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
    },
    body: {
      model: anthropicModelForTask(taskId),
      max_tokens: maxTokens,
      temperature,
      system,
      messages: [{ role: 'user', content: userPayload }],
    },
    json: true,
  });
}

async function invokeMagnixLlm(ctx, taskId, opts) {
  const primary = resolveProvider(taskId);
  const fallback = primary === 'deepseek' ? 'anthropic' : 'deepseek';
  const errors = [];

  for (const provider of [primary, fallback]) {
    if (!hasProvider(provider)) continue;
    try {
      if (provider === 'deepseek') {
        return await callDeepSeekLlm(ctx, opts);
      }
      return await callAnthropicLlm(ctx, { ...opts, taskId });
    } catch (e) {
      errors.push(`${provider}: ${e.message}`);
    }
  }

  if (!hasProvider('deepseek') && !hasProvider('anthropic')) {
    throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY trên n8n env');
  }
  throw new Error(errors.join(' | ') || 'LLM providers failed');
}

